namespace ProductReviewApp.Controllers
{
    public class ProductController : Controller
    {
        private ApplicationDbContext db = new ApplicationDbContext();

        public ActionResult Details(int id)
        {
            var product = db.Products
                .Include(p => p.Reviews)
                .FirstOrDefault(p => p.ProductId == id);

            if (product == null)
            {
                return HttpNotFound();
            }

            var viewModel = new ProductViewModel
            {
                ProductId = product.ProductId,
                ProductName = product.ProductName,
                Description = product.Description,
                Price = product.Price,
                Reviews = product.Reviews
                    .OrderByDescending(r => r.CreatedDate)
                    .Select(r => new ReviewViewModel
                    {
                        ReviewId = r.ReviewId,
                        UserName = r.UserName,
                        ReviewText = SanitizeAndFormatReview(r.ReviewText),
                        Rating = r.Rating,
                        CreatedDate = r.CreatedDate
                    }).ToList(),
                TotalReviews = product.Reviews.Count,
                AverageRating = product.Reviews.Any() ? product.Reviews.Average(r => r.Rating) : 0
            };

            return View(viewModel);
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult SubmitReview(SubmitReviewViewModel model)
        {
            if (ModelState.IsValid)
            {
                var review = new Review
                {
                    ProductId = model.ProductId,
                    UserName = model.UserName,
                    ReviewText = model.ReviewText,
                    Rating = model.Rating,
                    CreatedDate = DateTime.Now
                };

                db.Reviews.Add(review);
                db.SaveChanges();

                return RedirectToAction("Details", new { id = model.ProductId });
            }

            return RedirectToAction("Details", new { id = model.ProductId });
        }

        private string SanitizeAndFormatReview(string reviewText)
        {
            if (string.IsNullOrWhiteSpace(reviewText))
                return string.Empty;

            reviewText = System.Web.HttpUtility.HtmlEncode(reviewText);

            reviewText = System.Text.RegularExpressions.Regex.Replace(
                reviewText,
                @"\*\*(.+?)\*\*",
                "<strong>$1</strong>"
            );

            reviewText = System.Text.RegularExpressions.Regex.Replace(
                reviewText,
                @"\*(.+?)\*",
                "<em>$1</em>"
            );

            reviewText = System.Text.RegularExpressions.Regex.Replace(
                reviewText,
                @"__(.+?)__",
                "<strong>$1</strong>"
            );

            reviewText = System.Text.RegularExpressions.Regex.Replace(
                reviewText,
                @"_(.+?)_",
                "<em>$1</em>"
            );

            reviewText = reviewText.Replace("\n", "<br />");

            return reviewText;
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                db.Dispose();
            }
            base.Dispose(disposing);
        }
    }
}